const PROCESSING_FEE = 5;
const BASE_PREMIUM_PER_ITEM = 25;
const BLOCK_OF_THREE_DISCOUNT = 15;
const BLOCK_SIZE = 3;

type Scenario = { steps: { op: string; items: { type: string }[] }[] };

function countItemsByType(items: { type: string }[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
}

function basePremiumForGroup(count: number): number {
  const subtotal = count * BASE_PREMIUM_PER_ITEM;
  const discount = count === BLOCK_SIZE ? BLOCK_OF_THREE_DISCOUNT : 0;
  return subtotal - discount;
}

export function runScenario(scenario: unknown): unknown {
  const items = (scenario as Scenario).steps[0].items;
  const itemCountsByType = countItemsByType(items);
  let basePremium = 0;
  for (const count of itemCountsByType.values()) {
    basePremium += basePremiumForGroup(count);
  }
  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
}
